// HTML nümunəsi:
/*
<div id="outfitElement" class="summer trendy">Qəşəng köynək</div>
<button class="update-btn">Stili yenilə</button>
*/

// 1. className ilə işləmə
const outfitElement = document.getElementById("outfitElement");
console.log(outfitElement.className); // "summer trendy"

outfitElement.className = "winter sale"; // Bütün sinifləri dəyişdirir
// nəticə: <div id="outfitElement" class="winter sale">

outfitElement.className += " trendy"; // Yeni sinif əlavə etmək
// nəticə: <div id="outfitElement" class="winter sale trendy">

// 2. classList ilə işləmə
console.log(outfitElement.classList); // DOMTokenList ["winter", "sale", "trendy"]

outfitElement.classList.add("premium"); // Sinif əlavə etmək
// nəticə: <div id="outfitElement" class="winter sale trendy premium">

outfitElement.classList.remove("sale"); // Sinif silmək
// nəticə: <div id="outfitElement" class="winter trendy premium">

console.log(outfitElement.classList.contains("trendy")); // true
console.log(outfitElement.classList.contains("sale")); // false

outfitElement.classList.toggle("highlight"); // Əlavə edir (yoxdursa)
// nəticə: <div id="outfitElement" class="winter trendy premium highlight">
outfitElement.classList.toggle("highlight"); // Silir (varsa)
// nəticə: <div id="outfitElement" class="winter trendy premium">

// 3. Hadisə ilə dinamik yeniləmə
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  outfitElement.classList.toggle("special-offer");
  outfitElement.textContent = `Qəşəng köynək (${outfitElement.classList.contains("special-offer") ? "Xüsusi təklif!" : ""})`;
});
// nəticə: Düyməyə klikləyəndə special-offer sinfi əlavə olunur/silinir

// Təhlükə nümunəsi: className ilə səhv
const userInput = "hacked-class <script>alert('Hücum!')</script>";
outfitElement.className = userInput;
// Təhlükə: Zərərli sinif adları əlavə oluna bilər

// Təhlükəsiz alternativ: classList
const safeClass = "safe-style";
outfitElement.classList.add(safeClass);
// nəticə: <div id="outfitElement" class="winter trendy premium safe-style">

// Dinamik sinif manipulyasiyası
const updateStyles = () => {
  if (!outfitElement.classList.contains("featured")) {
    outfitElement.classList.add("featured");
    outfitElement.textContent = "Qəşəng köynək (Seçilmiş!)";
  } else {
    outfitElement.classList.remove("featured");
    outfitElement.textContent = "Qəşəng köynək";
  }
};
updateButton.addEventListener("click", updateStyles);
// nəticə: Düyməyə klikləyəndə featured sinfi əlavə olunur/silinir

