// HTML example:
/*
<div id="outfitElement" class="summer trendy">Stylish shirt</div>
<button class="update-btn">Update style</button>
*/

// 1. Working with className
const outfitElement = document.getElementById("outfitElement");
console.log(outfitElement.className); // "summer trendy"

outfitElement.className = "winter sale"; // Replaces all classes
// Output: <div id="outfitElement" class="winter sale">

outfitElement.className += " trendy"; // Adding a class
// Output: <div id="outfitElement" class="winter sale trendy">

// 2. Working with classList
console.log(outfitElement.classList); // DOMTokenList ["winter", "sale", "trendy"]

outfitElement.classList.add("premium"); // Add a class
// Output: <div id="outfitElement" class="winter sale trendy premium">

outfitElement.classList.remove("sale"); // Remove a class
// Output: <div id="outfitElement" class="winter trendy premium">

console.log(outfitElement.classList.contains("trendy")); // true
console.log(outfitElement.classList.contains("sale")); // false

outfitElement.classList.toggle("highlight"); // Add if absent
// Output: <div id="outfitElement" class="winter trendy premium highlight">
outfitElement.classList.toggle("highlight"); // Remove if present
// Output: <div id="outfitElement" class="winter trendy premium">

// 3. Dynamic update with event
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  outfitElement.classList.toggle("special-offer");
  outfitElement.textContent = `Stylish shirt (${outfitElement.classList.contains("special-offer") ? "Special offer!" : ""})`;
});
// Output: Clicking the button adds/removes special-offer class

// Danger example: className with unsafe input
const userInput = "hacked-class <script>alert('Attack!')</script>";
outfitElement.className = userInput;
// Danger: Malicious class names could be added

// Safe alternative: classList
const safeClass = "safe-style";
outfitElement.classList.add(safeClass);
// Output: <div id="outfitElement" class="winter trendy premium safe-style">

// Dynamic class manipulation
const updateStyles = () => {
  if (!outfitElement.classList.contains("featured")) {
    outfitElement.classList.add("featured");
    outfitElement.textContent = "Stylish shirt (Featured!)";
  } else {
    outfitElement.classList.remove("featured");
    outfitElement.textContent = "Stylish shirt";
  }
};
updateButton.addEventListener("click", updateStyles);
// Output: Clicking the button adds/removes featured class

