// Пример HTML:
/*
<div id="outfitElement" class="summer trendy">Стильная рубашка</div>
<button class="update-btn">Обновить стиль</button>
*/

// 1. Работа с className
const outfitElement = document.getElementById("outfitElement");
console.log(outfitElement.className); // "summer trendy"

outfitElement.className = "winter sale"; // Заменяет все классы
// Вывод: <div id="outfitElement" class="winter sale">

outfitElement.className += " trendy"; // Добавление класса
// Вывод: <div id="outfitElement" class="winter sale trendy">

// 2. Работа с classList
console.log(outfitElement.classList); // DOMTokenList ["winter", "sale", "trendy"]

outfitElement.classList.add("premium"); // Добавление класса
// Вывод: <div id="outfitElement" class="winter sale trendy premium">

outfitElement.classList.remove("sale"); // Удаление класса
// Вывод: <div id="outfitElement" class="winter trendy premium">

console.log(outfitElement.classList.contains("trendy")); // true
console.log(outfitElement.classList.contains("sale")); // false

outfitElement.classList.toggle("highlight"); // Добавить, если отсутствует
// Вывод: <div id="outfitElement" class="winter trendy premium highlight">
outfitElement.classList.toggle("highlight"); // Удалить, если присутствует
// Вывод: <div id="outfitElement" class="winter trendy premium">

// 3. Динамическое обновление с событием
const updateButton = document.querySelector(".update-btn");
updateButton.addEventListener("click", () => {
  outfitElement.classList.toggle("special-offer");
  outfitElement.textContent = `Стильная рубашка (${outfitElement.classList.contains("special-offer") ? "Специальное предложение!" : ""})`;
});
// Вывод: При клике на кнопку добавляется/удаляется класс special-offer

// Пример опасности: className с небезопасным вводом
const userInput = "hacked-class <script>alert('Атака!')</script>";
outfitElement.className = userInput;
// Опасность: Могут быть добавлены вредоносные имена классов

// Безопасная альтернатива: classList
const safeClass = "safe-style";
outfitElement.classList.add(safeClass);
// Вывод: <div id="outfitElement" class="winter trendy premium safe-style">

// Динамическое управление классами
const updateStyles = () => {
  if (!outfitElement.classList.contains("featured")) {
    outfitElement.classList.add("featured");
    outfitElement.textContent = "Стильная рубашка (Избранное!)";
  } else {
    outfitElement.classList.remove("featured");
    outfitElement.textContent = "Стильная рубашка";
  }
};
updateButton.addEventListener("click", updateStyles);
// Вывод: При клике на кнопку добавляется/удаляется класс featured

